const svg = $('#meet-svg'), z = $('#meet-z'), info = $('#meet-info');
const W=760, H=320;
function render(){
  svg.innerHTML = '';
  const t = +z.value / 100;            // 0 = affine, 1 = full perspective
  // affine plane drawn as a strip; perspective adds vanishing toward center
  // two parallel lines: y = 0.4 and y = -0.4, slope 0
  // we render them as quadrilaterals in screen space.
  const cx = W/2, cy = H*0.42;          // vanishing point on horizon
  // horizon line
  const hY = cy;
  if(t > 0.05){
    svg.appendChild(SVG('line',{x1:0,y1:hY,x2:W,y2:hY,stroke:'var(--line)','stroke-dasharray':'4 6','stroke-width':1.2}));
    const tx = SVG('text',{x:W-10,y:hY-6,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
    tx.textContent = 'line at infinity ℓ∞';
    svg.appendChild(tx);
  }
  // line A (top) and line B (bottom) in affine coords y = +/- 1
  // pixel y at horizontal x with depth d in [0,1]: lines diverge to the edges as d->0 and converge to vanishing point as d->1
  function project(s, yAff){
    // s in [-1,1] is along the rail; depth = (s+1)/2 * (1 - t) + t
    // when t=0 we have flat parallel lines; when t=1 they go to vanishing point.
    const screenX = cx + s * (W*0.46);
    // affine y: at t=0, y stays the same vertical separation (yAff*40)
    // at t=1, y collapses to (cy) at far end (s=1) and stays full at near end (s=-1)
    const farFrac = (s + 1) / 2;   // 0 at front, 1 at back
    // sep at this x: linearly interpolate from yAff*60 (front) to yAff*60*(1-t*farFrac)
    const sep = yAff * 60 * (1 - t * farFrac);
    const baseY = H*0.78;
    const screenY = baseY + sep - (baseY - hY) * t * farFrac;
    return [screenX, screenY];
  }
  function rail(yAff, color){
    const pts = [];
    for(let i=0;i<=40;i++){
      const s = -1 + 2*i/40;
      pts.push(project(s, yAff).join(','));
    }
    const pl = SVG('polyline',{points:pts.join(' '),stroke:color,'stroke-width':2,fill:'none'});
    svg.appendChild(pl);
  }
  // sleepers (cross ties) for visual flair when zooming out
  if(t > 0.15){
    for(let i=1;i<=8;i++){
      const s = -0.95 + 1.9*i/9;
      const a = project(s, 1), b = project(s, -1);
      svg.appendChild(SVG('line',{x1:a[0],y1:a[1],x2:b[0],y2:b[1],stroke:'#3a4252','stroke-width':1}));
    }
  }
  rail(1,  'var(--blue)');
  rail(-1, 'var(--green)');
  // mark the meeting point at the vanishing point as we zoom out
  if(t > 0.6){
    const op = Math.min(1, (t-0.6)/0.3);
    svg.appendChild(SVG('circle',{cx:cx,cy:hY,r:6,fill:'var(--yellow)','fill-opacity':op}));
    const tx = SVG('text',{x:cx+12,y:hY-10,'font-size':13,fill:'var(--yellow)','fill-opacity':op});
    tx.textContent = '[1:0:0]  — point at infinity for slope 0';
    svg.appendChild(tx);
  }
  // labels
  const lbl1 = SVG('text',{x:30,y:H*0.78+62,'font-size':12,fill:'var(--blue)'}); lbl1.textContent = 'y = +1';
  const lbl2 = SVG('text',{x:30,y:H*0.78-50,'font-size':12,fill:'var(--green)'}); lbl2.textContent = 'y = −1';
  svg.appendChild(lbl1); svg.appendChild(lbl2);
  info.textContent = t < 0.05 ? 'affine view: parallel lines never meet' :
                     t < 0.95 ? 'perspective view forming…' :
                                'projective view: both lines pass through the same point on ℓ∞';
}
z.addEventListener('input', render);
render();

