const svg = $('#defn-svg'), out = $('#defn-out');
const xR = $('#defn-x'), yR = $('#defn-y'), zR = $('#defn-z');
const cx = 310, cy = 150;
// simple oblique projection of (X,Y,Z) -> screen
// axes: X right, Y up, Z down-left
function P(X,Y,Z){
  return [cx + X*1.6 - Z*0.7, cy - Y*1.4 + Z*0.4];
}
function render(){
  svg.innerHTML = '';
  // axes
  function axis(p1, p2, color, label, lp){
    svg.appendChild(SVG('line',{x1:p1[0],y1:p1[1],x2:p2[0],y2:p2[1],stroke:color,'stroke-width':1,'stroke-dasharray':'3 4'}));
    const t = SVG('text',{x:lp[0],y:lp[1],'font-size':12,fill:color}); t.textContent = label; svg.appendChild(t);
  }
  axis(P(-130,0,0), P(130,0,0), 'var(--mute)', 'X', P(140,0,0));
  axis(P(0,-90,0), P(0,90,0), 'var(--mute)', 'Y', P(0,98,0));
  axis(P(0,0,-110), P(0,0,110), 'var(--mute)', 'Z', P(0,0,118));
  // the line through origin spanned by (X,Y,Z)
  const X = +xR.value, Y = +yR.value, Z = +zR.value;
  if(X===0 && Y===0 && Z===0){ out.textContent = 'origin not allowed'; return; }
  const k = 1.4;
  const a = P(-X*k, -Y*k, -Z*k), b = P(X*k, Y*k, Z*k);
  svg.appendChild(SVG('line',{x1:a[0],y1:a[1],x2:b[0],y2:b[1],stroke:'var(--yellow)','stroke-width':2.5}));
  // origin
  svg.appendChild(SVG('circle',{cx,cy,r:3,fill:'var(--ink)'}));
  // a representative point on the line
  const r = P(X,Y,Z);
  svg.appendChild(SVG('circle',{cx:r[0],cy:r[1],r:5,fill:'var(--blue)'}));
  const txt = SVG('text',{x:r[0]+8,y:r[1]-6,'font-size':12,fill:'var(--blue)'});
  txt.textContent = `(${X},${Y},${Z})`;
  svg.appendChild(txt);
  // a different scalar multiple
  const r2 = P(X*0.4, Y*0.4, Z*0.4);
  svg.appendChild(SVG('circle',{cx:r2[0],cy:r2[1],r:4,fill:'var(--green)'}));
  const t2 = SVG('text',{x:r2[0]+8,y:r2[1]+12,'font-size':12,fill:'var(--green)'});
  t2.textContent = `(0.4·X, 0.4·Y, 0.4·Z)`;
  svg.appendChild(t2);
  out.textContent = `[X : Y : Z] = [${X} : ${Y} : ${Z}]   — same point of P² as any non-zero scalar multiple`;
}
[xR,yR,zR].forEach(r => r.addEventListener('input', render));
render();

