function plot(svgId, eqFn, infoXY){
  // eqFn(x,y) -> 0 plotted in [-3,3] x [-3,3] using marching grid
  const svg = $('#'+svgId);
  svg.innerHTML = '';
  const W=220, H=200;
  const ox = W/2, oy = H/2, sc = 30;
  // grid axes
  svg.appendChild(SVG('line',{x1:0,y1:oy,x2:W,y2:oy,stroke:'#2a3242','stroke-width':1}));
  svg.appendChild(SVG('line',{x1:ox,y1:0,x2:ox,y2:H,stroke:'#2a3242','stroke-width':1}));
  // sample contour by sweeping x and finding y by approximate isolines
  // For these small finite curves we just plot polyline samples directly with parametric forms below.
  return svg;
}
function drawCircleConic(svgId, color){
  const svg = plot(svgId);
  const W=220, H=200, ox=W/2, oy=H/2, sc=50;
  const pts = [];
  for(let i=0;i<=120;i++){
    const t = 2*Math.PI*i/120;
    pts.push((ox + Math.cos(t)*sc) + ',' + (oy - Math.sin(t)*sc));
  }
  svg.appendChild(SVG('polyline',{points:pts.join(' '),stroke:color,'stroke-width':2,fill:'none'}));
  // axis labels
  const lx = SVG('text',{x:W-10,y:oy-4,'text-anchor':'end','font-size':10,fill:'var(--mute)'}); lx.textContent='x'; svg.appendChild(lx);
  const ly = SVG('text',{x:ox+4,y:10,'font-size':10,fill:'var(--mute)'}); ly.textContent='y'; svg.appendChild(ly);
}
function drawHyperbolaConic(svgId, color, sign){
  // Z=1: x²+y²=1 (circle).  Y=1: x²+1=z² → z²-x²=1 hyperbola.  X=1: 1+y²=z² same.
  const svg = plot(svgId);
  const W=220, H=200, ox=W/2, oy=H/2, sc=40;
  // hyperbola z²-x²=1 → z=±sqrt(1+x²)
  for(const sgn of [1,-1]){
    const pts = [];
    for(let i=0;i<=80;i++){
      const x = -2 + 4*i/80;
      const z = sgn*Math.sqrt(1 + x*x);
      const sx = ox + x*sc, sy = oy - z*sc;
      if(sy>=0 && sy<=H) pts.push(sx+','+sy);
    }
    svg.appendChild(SVG('polyline',{points:pts.join(' '),stroke:color,'stroke-width':2,fill:'none'}));
  }
  // asymptotes (these correspond to points at infinity)
  for(const m of [1,-1]){
    svg.appendChild(SVG('line',{x1:0, y1:oy + ox*m, x2:W, y2:oy - (W-ox)*m, stroke:'#444a5e','stroke-width':1,'stroke-dasharray':'3 4'}));
  }
  const lx = SVG('text',{x:W-10,y:oy-4,'text-anchor':'end','font-size':10,fill:'var(--mute)'}); lx.textContent='1st coord'; svg.appendChild(lx);
  const ly = SVG('text',{x:ox+4,y:10,'font-size':10,fill:'var(--mute)'}); ly.textContent='2nd coord'; svg.appendChild(ly);
}
drawCircleConic('ch-z', 'var(--blue)');
drawHyperbolaConic('ch-y', 'var(--green)');
drawHyperbolaConic('ch-x', 'var(--pink)');

const out = $('#ch-out');
const boxes = $$('.chartbox');
const txts = {
  Z: 'U_Z (Z=1):  x² + y² = 1.   Compact circle.   Points at infinity from this chart: [X:Y:0] with X²+Y²=0, i.e. only [1:i:0] and [1:-i:0] over C — none over R.',
  Y: 'U_Y (Y=1):  x² + 1 = z²,  i.e. z² − x² = 1.   Hyperbola.   The two missing points are where Y=0: [1:0:1] and [1:0:-1] are visible here, and [1:0:0] (the X-axis direction) is at infinity in this chart.',
  X: 'U_X (X=1):  1 + y² = z²,  i.e. z² − y² = 1.   Same hyperbola, different chart.   [0:1:0] (the Y-axis direction) is at infinity here.'
};
function pick(c){
  boxes.forEach(b => b.classList.toggle('sel', b.dataset.c === c));
  out.textContent = txts[c];
}
boxes.forEach(b => b.addEventListener('click', () => pick(b.dataset.c)));
pick('Z');

