const svg = $('#dir-svg'), out = $('#dir-out');
const W=720, H=300;
// left panel: affine A^2 with several parallel lines of given direction
// right panel: a circle representing ℓ∞ (= P^1(R) ≅ S^1/{±1}); the point [a:b:0] = direction (a,b) up to sign
const Lcx=180, Lcy=150, Lr=120;     // affine viewport center
const Rcx=540, Rcy=150, Rr=110;     // circle for ℓ∞
let theta = 0.7;
function render(){
  svg.innerHTML = '';
  // panel borders / titles
  const t1 = SVG('text',{x:Lcx,y:30,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
  t1.textContent = 'affine plane A²: parallel family of slope tan(θ)';
  const t2 = SVG('text',{x:Rcx,y:30,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
  t2.textContent = 'line at infinity ℓ∞ ≅ P¹(R) (antipodal points identified)';
  svg.appendChild(t1); svg.appendChild(t2);
  // left: axes
  svg.appendChild(SVG('line',{x1:Lcx-Lr,y1:Lcy,x2:Lcx+Lr,y2:Lcy,stroke:'#2a3242'}));
  svg.appendChild(SVG('line',{x1:Lcx,y1:Lcy-Lr,x2:Lcx,y2:Lcy+Lr,stroke:'#2a3242'}));
  // a few parallel lines through different points
  const a = Math.cos(theta), b = Math.sin(theta);
  for(let k=-3;k<=3;k++){
    // line through (k*Lr/4, 0) (perpendicular offset) with direction (a,b)
    // Use perpendicular offset
