function parse(s){
  s = s.replace(/\s+/g,'').replace(/-/g,'+-');
  if(s.startsWith('+')) s = s.slice(1);
  const monos = s.split('+').filter(Boolean);
  const out = [];
  for(let m of monos){
    let sign = 1;
    if(m.startsWith('-')){ sign = -1; m = m.slice(1); }
    // coefficient
    let coef = 1;
    const cMatch = m.match(/^(\d+(?:\.\d+)?)/);
    if(cMatch){ coef = parseFloat(cMatch[1]); m = m.slice(cMatch[1].length); }
