    if(m.startsWith('*')) m = m.slice(1);
    // x^i and y^j
    let i=0, j=0;
    const parts = m.split('*').filter(Boolean);
    for(const p of parts){
      const xm = p.match(/^x(?:\^(\d+))?$/);
      const ym = p.match(/^y(?:\^(\d+))?$/);
      if(xm){ i += xm[1] ? +xm[1] : 1; }
      else if(ym){ j += ym[1] ? +ym[1] : 1; }
      else if(p === ''){ /* skip */ }
      else if(/^\d+(\.\d+)?$/.test(p)){ coef *= parseFloat(p); }
      else { throw new Error('bad token: ' + p); }
    }
    if(parts.length === 0 && !cMatch){ throw new Error('empty monomial'); }
    out.push({c: sign*coef, i, j});
  }
