  if(i){ s += 'X' + (i>1 ? '^'+i : ''); }
  if(j){ s += 'Y' + (j>1 ? '^'+j : ''); }
  if(k){ s += 'Z' + (k>1 ? '^'+k : ''); }
  if(s === '') s = '1';
  return s;
}
