function plotY(){
  const svg = $('#we-y'); svg.innerHTML='';
  // (u,t) plane, u = X/Y, t = Z/Y
  // equation:  u² t = 1 + t³  =>  u² = (1 + t³)/t   (for t≠0)
  // at t=0 we have the point [0:1:0] = (u=0, t=0)
  // and the curve passes through it: as t→0+, u² ~ 1/t → ∞ on the branch u² = (1+t³)/t but also there's a different branch
  // Actually the projective closure passes through (u,t)=(0,0) smoothly: rewrite as 1 = u²t - t³.
  // Implicit plot: F(u,t) = u² t - t³ - 1 = 0. Use marching squares-lite over a grid.
  const W=320, H=280, ox=W/2, oy=H/2, sc=70;
  svg.appendChild(SVG('line',{x1:0,y1:oy,x2:W,y2:oy,stroke:'#2a3242'}));
  svg.appendChild(SVG('line',{x1:ox,y1:0,x2:ox,y2:H,stroke:'#2a3242'}));
  function f(u,t){ return u*u*t - t*t*t - 1; }
  // sample a fine grid and connect zero crossings
  const N=200;
  const lo=-2.2, hi=2.2;
  const seg = [];
  for(let i=0;i<N;i++){
    for(let j=0;j<N;j++){
      const u0 = lo + (hi-lo)*i/N, u1 = lo + (hi-lo)*(i+1)/N;
      const t0 = lo + (hi-lo)*j/N, t1 = lo + (hi-lo)*(j+1)/N;
      const v00 = f(u0,t0), v10 = f(u1,t0), v01 = f(u0,t1), v11 = f(u1,t1);
      const sgns = [v00,v10,v11,v01].map(v => v>0?1:-1);
      const min = Math.min(...sgns), max = Math.max(...sgns);
      if(min === max) continue;
      // approximate: take cell center
      const u = (u0+u1)/2, t = (t0+t1)/2;
      const sx = ox + u*sc, sy = oy - t*sc;
      seg.push([sx,sy]);
    }
  }
  seg.forEach(([sx,sy]) => {
    svg.appendChild(SVG('circle',{cx:sx,cy:sy,r:0.9,fill:'var(--green)'}));
  });
  // mark the identity point O = (0,0) in this chart
  svg.appendChild(SVG('circle',{cx:ox, cy:oy, r:5, fill:'var(--yellow)', stroke:'#000','stroke-width':1}));
  const tx = SVG('text',{x:ox+8,y:oy-6,'font-size':12,fill:'var(--yellow)'});
  tx.textContent = 'O = (0,0)  ←  was at infinity in U_Z';
  svg.appendChild(tx);
  // axis labels
  const lx = SVG('text',{x:W-10,y:oy-4,'text-anchor':'end','font-size':11,fill:'var(--mute)'}); lx.textContent='u = X/Y'; svg.appendChild(lx);
  const ly = SVG('text',{x:ox+4,y:12,'font-size':11,fill:'var(--mute)'}); ly.textContent='t = Z/Y'; svg.appendChild(ly);
}
