// U_Z chart: usual xy plot
// U_Y chart (Y=1): u² t = 1 + t³ where u = X/Y, t = Z/Y;  i.e.  u² = (1 + t³)/t ;  also  t = 0 corresponds to Y=∞ direction... wait: Z/Y = t; at the point [0:1:0] we have t = 0, u = 0. Plot in (u,t).
function plotZ(){
  const svg = $('#we-z'); svg.innerHTML='';
  const W=320, H=280, ox=W/2, oy=H/2, sc=42;
  svg.appendChild(SVG('line',{x1:0,y1:oy,x2:W,y2:oy,stroke:'#2a3242'}));
  svg.appendChild(SVG('line',{x1:ox,y1:0,x2:ox,y2:H,stroke:'#2a3242'}));
  // y² = x³ + 1: real for x ≥ -1
  const upper=[], lower=[];
  for(let i=0;i<=200;i++){
    const x = -1 + 4*i/200;
    const r = x*x*x + 1;
    if(r < 0) continue;
    const y = Math.sqrt(r);
    const sx = ox + x*sc;
    upper.push(sx + ',' + (oy - y*sc));
    lower.push(sx + ',' + (oy + y*sc));
  }
  svg.appendChild(SVG('polyline',{points:upper.join(' '),stroke:'var(--blue)','stroke-width':2,fill:'none'}));
  svg.appendChild(SVG('polyline',{points:lower.join(' '),stroke:'var(--blue)','stroke-width':2,fill:'none'}));
  // the "missing" identity O lives at infinity (vertical direction)
  const tx = SVG('text',{x:ox+6,y:14,'font-size':11,fill:'var(--yellow)'});
  tx.textContent = 'O = [0:1:0] is at infinity ↑';
  svg.appendChild(tx);
  // arrows up/down
  drawArrow(svg, [ox+sc*1.7, oy-sc*2.6], [ox+sc*1.7, 6], {color:'var(--yellow)', markerId:'we-up', dash:'4 4'});
}
